const r = msg.payload;

const f32 = i => {
    if (!r || r[i] === undefined || r[i + 1] === undefined) {
        return null;
    }
    const b = Buffer.alloc(4);
    b.writeUInt16BE(r[i], 0);
    b.writeUInt16BE(r[i + 1], 2);
    return b.readFloatBE(0);
};

msg.payload = {
    v_l1: f32(0),
    v_l2: f32(2),
    v_l3: f32(4),

    i_l1: f32(6),
    i_l2: f32(8),
    i_l3: f32(10),

    // Keep old names
    p: f32(12),
    q: f32(14),
    s: f32(16),
    pf: f32(18),

    freq: f32(20),
    thd_v: f32(22),
    thd_i: f32(24),

    p_l1: f32(26),
    p_l2: f32(28),
    p_l3: f32(30),

    pf_l1: f32(32),
    pf_l2: f32(34),
    pf_l3: f32(36),

    kwh: f32(38),
    kvarh: f32(40),
    demand: f32(42),

    // Add cleaner aliases for the JSON/historian path
    p_kw: f32(12),
    q_kvar: f32(14),
    s_kva: f32(16),
    freq_hz: f32(20),
    thd_v_pct: f32(22),
    thd_i_pct: f32(24),
    p_l1_kw: f32(26),
    p_l2_kw: f32(28),
    p_l3_kw: f32(30),
    demand_kw: f32(42),

    // APFC closed-loop diagnostic registers
    apfc_pf_before: f32(44),
    apfc_pf_after: f32(46),
    apfc_q_cap_kvar: f32(48),
    apfc_steps_active: f32(50),
    apfc_target_pf: f32(52),
    apfc_q_before_kvar: f32(54),
    apfc_q_after_kvar: f32(56)
};

msg.topic = "Incomer";
return msg;

