  ["L1/P_kW", d.p_l1, "kW"], ["L2/P_kW", d.p_l2, "kW"], ["L3/P_kW", d.p_l3, "kW"],
  ["L1/PF", d.pf_l1, ""], ["L2/PF", d.pf_l2, ""], ["L3/PF", d.pf_l3, ""],
];
msg.payload = { metrics: rows.map(r => ({ name: r[0], value: r[1] })) };
if (!context.get("defined")) {           // send definitions ONCE only
  const def = {};
  for (const r of rows) def[r[0]] = { dataType: "Double", properties: { engUnits: { type: "String", value: r[2] } } };
  msg.definition = def;
  context.set("defined", true);
}
return msg;

