let p = msg.payload;

function pick(...keys) {
    for (let k of keys) {
        if (p[k] !== undefined && p[k] !== null) return Number(p[k]);
    }
    return null;
}

let v_l1 = pick("v_l1");
let v_l2 = pick("v_l2");
let v_l3 = pick("v_l3");

let i_l1 = pick("i_l1");
let i_l2 = pick("i_l2");
let i_l3 = pick("i_l3");

let pf = pick("pf", "pf_tot", "power_factor", "power_factor_total");

let s_kva = pick("s_kva", "s_tot", "apparent_power", "apparent_power_total");
let p_kw = pick("p_kw", "p_tot", "active_power", "active_power_total");
let q_kvar = pick("q_kvar", "q_tot", "reactive_power", "reactive_power_total");

if (s_kva === null && v_l1 !== null && v_l2 !== null && v_l3 !== null && i_l1 !== null && i_l2 !== null && i_l3 !== null) {
    s_kva = ((v_l1 * i_l1) + (v_l2 * i_l2) + (v_l3 * i_l3)) / 1000.0;
}

if (p_kw === null && s_kva !== null && pf !== null) {
    p_kw = s_kva * pf;
}

if (q_kvar === null && s_kva !== null && p_kw !== null) {
    q_kvar = Math.sqrt(Math.max((s_kva * s_kva) - (p_kw * p_kw), 0));
}

// APFC fields from the extended Incomer register block
let apfc_pf_before = pick("apfc_pf_before", "pf_before");
let apfc_pf_after = pick("apfc_pf_after", "pf_after");
let apfc_q_cap_kvar = pick("apfc_q_cap_kvar", "q_cap_kvar", "capacitor_kvar");
let apfc_steps_active = pick("apfc_steps_active", "steps_active");
let apfc_target_pf = pick("apfc_target_pf", "target_pf");
let apfc_q_before_kvar = pick("apfc_q_before_kvar", "q_before_kvar");
let apfc_q_after_kvar = pick("apfc_q_after_kvar", "q_after_kvar");

// In the APFC emulator, normal pf is already the corrected/incomer-side PF.
// This fallback keeps the JSON usable even if apfc_pf_after is not present.
if (apfc_pf_after === null && pf !== null) {
    apfc_pf_after = pf;
}

msg.topic = "uns/json/energy/Incomer";

msg.payload = JSON.stringify({
    v_l1: v_l1,
    v_l2: v_l2,
    v_l3: v_l3,

    i_l1: i_l1,
    i_l2: i_l2,
    i_l3: i_l3,

    p_kw: p_kw,
    q_kvar: q_kvar,
    s_kva: s_kva,
    pf: pf,

    freq_hz: pick("freq_hz", "freq", "frequency"),

    thd_v_pct: pick("thd_v_pct", "thd_v"),
    thd_i_pct: pick("thd_i_pct", "thd_i"),

    p_l1_kw: pick("p_l1_kw", "p_l1"),
    p_l2_kw: pick("p_l2_kw", "p_l2"),
    p_l3_kw: pick("p_l3_kw", "p_l3"),

    pf_l1: pick("pf_l1"),
    pf_l2: pick("pf_l2"),
    pf_l3: pick("pf_l3"),

    kwh: pick("kwh"),
    kvarh: pick("kvarh"),
    demand_kw: pick("demand_kw", "demand"),

    apfc_pf_before: apfc_pf_before,
    apfc_pf_after: apfc_pf_after,
    apfc_q_cap_kvar: apfc_q_cap_kvar,
    apfc_steps_active: apfc_steps_active,
    apfc_target_pf: apfc_target_pf,
    apfc_q_before_kvar: apfc_q_before_kvar,
    apfc_q_after_kvar: apfc_q_after_kvar
});

return msg;

